  'about.milestone.2016': { en: 'First TV partnership with MotorsTV', de: 'Erste TV-Partnerschaft mit MotorsTV', es: 'Primera asociación de TV con MotorsTV', pt: 'Primeira parceria de TV com MotorsTV', fr: 'Premier partenariat TV avec MotorsTV', it: 'Prima partnership TV con MotorsTV' },
