  'about.milestone.2019': { en: 'BMW SIM Live event in Munich', de: 'BMW SIM Live Event in München', es: 'Evento BMW SIM Live en Múnich', pt: 'Evento BMW SIM Live em Munique', fr: 'Événement BMW SIM Live à Munich', it: 'Evento BMW SIM Live a Monaco' },
  'about.milestone.2021': { en: 'Racespot GmbH officially registered in Cologne', de: 'Racespot GmbH offiziell in Köln eingetragen', es: 'Racespot GmbH registrada oficialmente en Colonia', pt: 'Racespot GmbH oficialmente registrada em Colônia', fr: 'Racespot GmbH officiellement enregistrée à Cologne', it: 'Racespot GmbH ufficialmente registrata a Colonia' },
  'about.milestone.2023': { en: 'Expanded to 8 broadcast languages', de: 'Auf 8 Broadcast-Sprachen erweitert', es: 'Ampliado a 8 idiomas de transmisión', pt: 'Expandido para 8 idiomas de transmissão', fr: 'Extension à 8 langues de diffusion', it: 'Espansione a 8 lingue di trasmissione' },
  'about.milestone.2024': { en: 'Surpassed 400+ events per year', de: 'Über 400 Events pro Jahr überschritten', es: 'Superados los 400+ eventos al año', pt: 'Superados 400+ eventos por ano', fr: 'Plus de 400 événements par an dépassés', it: 'Superati 400+ eventi all\'anno' },
