  'team.hugo.role':    { en: 'Founder & Producer', de: 'Gründer & Produzent', es: 'Fundador y Productor', pt: 'Fundador e Produtor', fr: 'Fondateur et Producteur', it: 'Fondatore e Produttore' },
  'team.hugo.bio':     { en: 'iRacing World Champion 2011. Combines elite racing knowledge with world-class production expertise.', de: 'iRacing-Weltmeister 2011. Vereint Elite-Rennwissen mit erstklassiger Produktionskompetenz.', es: 'Campeón mundial de iRacing 2011. Combina conocimiento de carreras de élite con experiencia de producción de clase mundial.', pt: 'Campeão mundial de iRacing 2011. Combina conhecimento de corrida de elite com experiência de produção de classe mundial.', fr: 'Champion du monde iRacing 2011. Allie expertise de course d\'élite et compétences de production de classe mondiale.', it: 'Campione del mondo iRacing 2011. Combina conoscenza delle corse d\'élite con competenze di produzione di livello mondiale.' },
  'team.philip.role':  { en: 'CEO & Co-Founder', de: 'Geschäftsführer & Mitgründer', es: 'CEO y Co-Fundador', pt: 'CEO e Co-Fundador', fr: 'PDG et Co-Fondateur', it: 'CEO e Co-Fondatore' },
  'team.philip.bio':   { en: "Simracing pioneer since 1997. Built Racespot into the world's leading simracing broadcast studio over 10+ years.", de: 'Simracing-Pionier seit 1997. Hat Racespot in über 10 Jahren zum weltweit führenden Simracing-Broadcast-Studio aufgebaut.', es: 'Pionero del simracing desde 1997. Construyó Racespot como el estudio de transmisión de simracing líder mundial en más de 10 años.', pt: 'Pioneiro do simracing desde 1997. Construiu a Racespot como o estúdio de transmissão de simracing líder mundial em mais de 10 anos.', fr: 'Pionnier du simracing depuis 1997. A construit Racespot en tant que studio de diffusion simracing leader mondial en plus de 10 ans.', it: 'Pioniere del simracing dal 1997. Ha costruito Racespot come lo studio di trasmissione simracing leader mondiale in oltre 10 anni.' },
  'team.aaron.role':   { en: 'Head of Sales & Marketing', de: 'Leiter Vertrieb & Marketing', es: 'Director de Ventas y Marketing', pt: 'Diretor de Vendas e Marketing', fr: 'Directeur des Ventes et du Marketing', it: 'Direttore Vendite e Marketing' },
  'team.aaron.bio':    { en: "EMM General Manager and sponsorship expert. Builds the partnerships that power Racespot's global reach.", de: 'EMM General Manager und Sponsoring-Experte. Baut die Partnerschaften auf, die Racespots globale Reichweite antreiben.', es: 'Gerente General de EMM y experto en patrocinios. Construye las asociaciones que impulsan el alcance global de Racespot.', pt: 'Gerente Geral da EMM e especialista em patrocínios. Constrói as parcerias que impulsionam o alcance global da Racespot.', fr: 'Directeur Général d\'EMM et expert en sponsoring. Construit les partenariats qui alimentent la portée mondiale de Racespot.', it: 'General Manager EMM ed esperto di sponsorizzazioni. Costruisce le partnership che alimentano la portata globale di Racespot.' },

