  'eventDetail.raceweek.desc1': { en: "RACE WEEK 2026 is Europe's new festival of virtual motorsport — bringing together the world's best sim racers, automotive brands, and gaming culture under one roof in Cologne, Germany.", de: 'RACE WEEK 2026 ist Europas neues Festival für virtuellen Motorsport — vereint die besten Simracer der Welt, Automobilmarken und Gaming-Kultur unter einem Dach in Köln.', es: 'RACE WEEK 2026 es el nuevo festival europeo de automovilismo virtual — reuniendo a los mejores simracers del mundo, marcas automotrices y cultura gaming bajo un mismo techo en Colonia, Alemania.', pt: 'RACE WEEK 2026 é o novo festival europeu de automobilismo virtual — reunindo os melhores simracers do mundo, marcas automotivas e cultura gamer sob o mesmo teto em Colônia, Alemanha.', fr: 'RACE WEEK 2026 est le nouveau festival européen du sport automobile virtuel — rassemblant les meilleurs simracers du monde, les marques automobiles et la culture gaming sous un même toit à Cologne, en Allemagne.', it: 'RACE WEEK 2026 è il nuovo festival europeo del motorsport virtuale — riunisce i migliori simracer del mondo, brand automobilistici e cultura gaming sotto un unico tetto a Colonia, Germania.' },
  'eventDetail.raceweek.desc2': { en: 'Five days of esports competition, live broadcasts, industry panels, hands-on experiences, and entertainment for up to 1,500 visitors per day. Produced by Racespot Media House.', de: 'Fünf Tage Esports-Wettbewerb, Live-Broadcasts, Branchenpanels, Hands-on-Erlebnisse und Entertainment für bis zu 1.500 Besucher pro Tag. Produziert von Racespot Media House.', es: 'Cinco días de competición de esports, transmisiones en vivo, paneles de la industria, experiencias prácticas y entretenimiento para hasta 1.500 visitantes por día. Producido por Racespot Media House.', pt: 'Cinco dias de competição de esports, transmissões ao vivo, painéis da indústria, experiências práticas e entretenimento para até 1.500 visitantes por dia. Produzido pela Racespot Media House.', fr: 'Cinq jours de compétition esport, diffusions en direct, tables rondes industrielles, expériences pratiques et divertissement pour jusqu\'à 1 500 visiteurs par jour. Produit par Racespot Media House.', it: 'Cinque giorni di competizione esport, trasmissioni live, panel di settore, esperienze pratiche e intrattenimento per fino a 1.500 visitatori al giorno. Prodotto da Racespot Media House.' },
  'eventDetail.highlights': { en: 'Event Highlights', de: 'Event-Highlights', es: 'Destacados del evento', pt: 'Destaques do evento', fr: "Points forts de l'événement", it: "Punti salienti dell'evento" },
